args.cypher:
// Find all AAS shells and their assets to locate the transport robot in Hall 4
MATCH (aas:AssetAdministrationShell)-[:MANAGES_ASSET]->(asset:Asset)
RETURN aas.id AS aasId, aas.idShort AS aasIdShort, asset.globalAssetId AS globalAssetId, asset.assetType AS assetType

// Find shells that are transport robots / AGVs in Hall 4
// First, find the FacilityInformation submodel for Hall 4
MATCH (sm:Submodel)-[:HAS_SEMANTIC_ID]->(:SemanticConcept {id: 'https://admin-shell.io/dfki/SubmodelTemplate/FacilityInformation/1/0'})
MATCH (aas:AssetAdministrationShell)-[:HAS_SUBMODEL]->(sm)
CALL {
  WITH sm
  MATCH (sm)-[:HAS_ELEMENT*]->(hallProp:Property)
  WHERE hallProp.idShort = 'HallIdentifier' OR hallProp.idShort = 'Name'
  RETURN hallProp.idShort AS propId, hallProp.value AS propValue LIMIT 1
}
RETURN aas.idShort, aas.id, sm.idShort AS facilitySmIdShort, collect(DISTINCT {id: propId, value: propValue}) AS hallProps

// Verify MiR100_001 is an AGV and get its AAS ID
MATCH (aas:AssetAdministrationShell {id: 'urn:aas:mir100:001'})-[:DERIVED_FROM]->(typeAAS:AssetAdministrationShell)
RETURN aas.idShort, aas.id, typeAAS.idShort, typeAAS.id
